{
  "name": "Arabic Handwritten Attendance Converter",
  "description": "An AI-powered system that extracts structured data from handwritten Arabic attendance sheets and exports them to Excel.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type Role = 'Admin' | 'HR User';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
}

export interface ConfidenceValue<T> {
  value: T;
  confidence: number;
}

export interface AttendanceRecord {
  date: string; // ISO format YYYY-MM-DD
  check_in: ConfidenceValue<string | null>;
  check_out: ConfidenceValue<string | null>;
}

export interface EmployeeExtraction {
  employee_name: ConfidenceValue<string>;
  records: AttendanceRecord[];
}

export interface ExtractionResult {
  employees: EmployeeExtraction[];
}

export enum FileStatus {
  Processing = 'Processing',
  Completed = 'Completed',
  Failed = 'Failed'
}

export interface AttendanceFile {
  id: string;
  name: string;
  uploaded_by: string;
  upload_date: string;
  status: FileStatus;
  data?: ExtractionResult;
  previewUrl?: string;
}

export interface AppState {
  user: User | null;
  files: AttendanceFile[];
  language: 'ar' | 'en';
  darkMode: boolean;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractionResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_PROMPT = `
You are an advanced Arabic document analysis AI specialized in extracting structured data from handwritten Arabic attendance sheets.
Your task is to:
1. Detect table structure visually.
2. Extract handwritten Arabic names.
3. Extract attendance dates from headers. Note: Headers like "2/9" mean Feb 9th or 9 فبراير. "2/8" means Feb 8th.
4. Extract check-in (حضور) and check-out (انصراف) times.
5. Normalize all times into HH:MM 24-hour format.
6. Output structured JSON only.
7. Include confidence score (0–100) per extracted cell.

Intelligence Normalization Rules:
- Handle messy handwriting.
- Handle Arabic digits (٠١٢٣٤٥٦٧٨٩) and Western digits (0123456789).
- Time formats like: ٨١٥, 815, ٨:١٥, 8:15, ٨٫١٥ -> 08:15.
- If hours > 23 or minutes > 59, mark low confidence.
- Correct obvious OCR digit confusion (e.g., ١ and ٧, ٥ and ٠).
- Never guess names if unreadable — mark as null with low confidence.
- Maintain row-to-row alignment.
- Detect column headers even if slightly misaligned.
- Convert date format to ISO YYYY-MM-DD.

Output must be valid JSON only.
`;

const USER_PROMPT = `
Analyze this scanned handwritten Arabic attendance sheet.
Tasks:
1. Detect the full table structure.
2. Identify:
   - Employee names column (usually first column on right side in RTL).
   - Dates at top row. For each date: حضور (check-in) and انصراف (check-out).
3. Extract all rows into structured format.
4. Convert times to HH:MM. If "٨١٥" -> "08:15".
5. Return JSON following the required schema.
`;

const EXTRACTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    employees: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employee_name: {
            type: Type.OBJECT,
            properties: {
              value: { type: Type.STRING },
              confidence: { type: Type.NUMBER }
            },
            required: ["value", "confidence"]
          },
          records: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                check_in: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                },
                check_out: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                }
              },
              required: ["date", "check_in", "check_out"]
            }
          }
        },
        required: ["employee_name", "records"]
      }
    }
  },
  required: ["employees"]
};

export async function extractAttendanceData(imageBase64: string): Promise<ExtractionResult> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: USER_PROMPT },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64.split(',')[1] || imageBase64,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: EXTRACTION_SCHEMA as any,
      },
    });

    const text = response.text || '';
    return JSON.parse(text);
  } catch (error) {
    console.error("Extraction error:", error);
    throw new Error("Failed to process the image. Please ensure it is clear and try again.");
  }
}

import * as XLSX from 'xlsx';
import { ExtractionResult } from '../types';

export function exportToExcel(data: ExtractionResult, fileName: string) {
  const wb = XLSX.utils.book_new();

  // Format data for sheet
  // Headers should be: [Name, Date1 (In), Date1 (Out), Date2 (In), Date2 (Out)...]
  const rows: any[] = [];

  // Get all unique dates for headers
  const allDatesSet = new Set<string>();
  data.employees.forEach(emp => {
    emp.records.forEach(rec => allDatesSet.add(rec.date));
  });
  const sortedDates = Array.from(allDatesSet).sort();

  const headers = ['اسم الموظف'];
  sortedDates.forEach(date => {
    headers.push(`${date} (حضور)`);
    headers.push(`${date} (انصراف)`);
  });

  rows.push(headers);

  data.employees.forEach(emp => {
    const row: any[] = [emp.employee_name.value];
    sortedDates.forEach(date => {
      const record = emp.records.find(r => r.date === date);
      row.push(record?.check_in.value || '');
      row.push(record?.check_out.value || '');
    });
    rows.push(row);
  });

  const ws = XLSX.utils.aoa_to_sheet(rows);

  // Set sheet direction to RTL
  if (!ws['!views']) ws['!views'] = [];
  ws['!views'].push({ RTL: true });

  XLSX.utils.book_append_sheet(wb, ws, 'Attendance');
  XLSX.writeFile(wb, `${fileName}.xlsx`);
}

