import React from 'react';
import { ExtractionResult, EmployeeExtraction } from '../types';
import { TRANSLATIONS } from '../constants';

interface AttendanceTableProps {
  data: ExtractionResult;
  language: 'ar' | 'en';
  darkMode: boolean;
  onUpdate: (updatedData: ExtractionResult) => void;
}

const AttendanceTable: React.FC<AttendanceTableProps> = ({ data, language, darkMode, onUpdate }) => {
  const t = TRANSLATIONS[language];

  // Get all unique dates for headers
  const allDatesSet = new Set<string>();
  data.employees.forEach(emp => {
    emp.records.forEach(rec => allDatesSet.add(rec.date));
  });
  const sortedDates = Array.from(allDatesSet).sort();

  const handleCellChange = (empIndex: number, dateIndex: number, type: 'check_in' | 'check_out' | 'name', newValue: string) => {
    const newData = { ...data };
    if (type === 'name') {
      newData.employees[empIndex].employee_name.value = newValue;
    } else {
      const record = newData.employees[empIndex].records.find(r => r.date === sortedDates[dateIndex]);
      if (record) {
        record[type].value = newValue;
      }
    }
    onUpdate(newData);
  };

  const getConfidenceColor = (confidence: number) => {
    if (confidence < 75) return 'bg-red-100 text-red-900 border-red-300';
    if (confidence < 90) return 'bg-yellow-100 text-yellow-900 border-yellow-300';
    return '';
  };

  return (
    <div className="overflow-x-auto rounded-xl border border-gray-200 shadow-sm">
      <table className={`w-full text-sm text-right ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
        <thead className={`${darkMode ? 'bg-gray-800' : 'bg-gray-100'} text-xs uppercase font-bold`}>
          <tr>
            <th className="px-6 py-4 sticky right-0 bg-inherit border-l">{t.employeeName}</th>
            {sortedDates.map(date => (
              <React.Fragment key={date}>
                <th className="px-6 py-4 border-l text-center" colSpan={2}>{date}</th>
              </React.Fragment>
            ))}
          </tr>
          <tr className="border-t border-gray-300">
            <th className="px-6 py-2 sticky right-0 bg-inherit border-l"></th>
            {sortedDates.map(date => (
              <React.Fragment key={`${date}-sub`}>
                <th className="px-2 py-2 border-l text-center min-w-[100px]">{t.checkIn}</th>
                <th className="px-2 py-2 border-l text-center min-w-[100px]">{t.checkOut}</th>
              </React.Fragment>
            ))}
          </tr>
        </thead>
        <tbody>
          {data.employees.map((emp, empIdx) => (
            <tr key={empIdx} className={`border-b ${darkMode ? 'border-gray-700 hover:bg-gray-850' : 'hover:bg-gray-50'}`}>
              <td className="px-4 py-3 sticky right-0 bg-inherit border-l">
                <input
                  type="text"
                  value={emp.employee_name.value}
                  onChange={(e) => handleCellChange(empIdx, 0, 'name', e.target.value)}
                  className={`w-full p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(emp.employee_name.confidence)}`}
                />
              </td>
              {sortedDates.map((date, dateIdx) => {
                const record = emp.records.find(r => r.date === date);
                return (
                  <React.Fragment key={`${empIdx}-${date}`}>
                    <td className="px-2 py-3 border-l text-center">
                      <input
                        type="text"
                        value={record?.check_in.value || ''}
                        onChange={(e) => handleCellChange(empIdx, dateIdx, 'check_in', e.target.value)}
                        className={`w-full text-center p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(record?.check_in.confidence || 0)}`}
                        placeholder="--:--"
                      />
                    </td>
                    <td className="px-2 py-3 border-l text-center">
                      <input
                        type="text"
                        value={record?.check_out.value || ''}
                        onChange={(e) => handleCellChange(empIdx, dateIdx, 'check_out', e.target.value)}
                        className={`w-full text-center p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(record?.check_out.confidence || 0)}`}
                        placeholder="--:--"
                      />
                    </td>
                  </React.Fragment>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AttendanceTable;

