   - Dates at top row. For each date: حضور (check-in) and انصراف (check-out).
3. Extract all rows into structured format.
4. Convert times to HH:MM.
5. Return JSON following the required schema.

NAME DICTIONARY FOR REFERENCE:
{{DICTIONARY}}
`;

const EXTRACTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    employees: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employee_name: {
            type: Type.OBJECT,
            properties: {
              value: { type: Type.STRING },
              confidence: { type: Type.NUMBER }
            },
            required: ["value", "confidence"]
          },
          records: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                check_in: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                },
                check_out: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                }
              },
              required: ["date", "check_in", "check_out"]
            }
          }
        },
        required: ["employee_name", "records"]
      }
    }
  },
  required: ["employees"]
};

export async function extractAttendanceData(
  imageBase64: string, 
  mimeType: string = 'image/jpeg',
  nameDictionary: string[] = []
): Promise<ExtractionResult> {
  try {
    const base64Data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const dictionaryString = nameDictionary.length > 0 ? nameDictionary.join(', ') : 'No specific names provided.';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: USER_PROMPT.replace('{{DICTIONARY}}', dictionaryString) },
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: EXTRACTION_SCHEMA as any,
      },
    });

    const text = response.text || '';
    if (!text) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(text);
  } catch (error) {
    console.error("Extraction error details:", error);
    throw new Error(`Failed to process the document: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
}

