const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('appState');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.nameDictionary) parsed.nameDictionary = [];
        return parsed;
      } catch (e) {
        console.error("Failed to parse saved state", e);
      }
    }
    return {
      user: null,
      files: [],
      nameDictionary: [],
      language: 'ar',
      darkMode: false
    };
  });

  const [currentView, setCurrentView] = useState<'dashboard' | 'review' | 'dictionary'>('dashboard');
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('appState', JSON.stringify(state));
  }, [state]);

  const handleLogin = (user: User) => setState(prev => ({ ...prev, user }));
  const handleLogout = () => {
    setState(prev => ({ ...prev, user: null }));
    setCurrentView('dashboard');
  };
  const handleLanguageToggle = () => setState(prev => ({ ...prev, language: prev.language === 'ar' ? 'en' : 'ar' }));
  const handleThemeToggle = () => setState(prev => ({ ...prev, darkMode: !prev.darkMode }));

  const handleAddName = (name: string) => {
    if (state.nameDictionary.includes(name)) {
      alert(TRANSLATIONS[state.language].nameExists);
      return;
    }
    setState(prev => ({ ...prev, nameDictionary: [...prev.nameDictionary, name] }));
  };

  const handleDeleteName = (name: string) => {
    setState(prev => ({ ...prev, nameDictionary: prev.nameDictionary.filter(n => n !== name) }));
  };

  const processFile = async (fileId: string, base64: string, mimeType: string) => {
    try {
      const result = await extractAttendanceData(base64, mimeType, state.nameDictionary);
      setState(prev => ({
        ...prev,
        files: prev.files.map(f => f.id === fileId ? { ...f, status: FileStatus.Completed, data: result } : f)
      }));
    } catch (error) {
      console.error("Processing failed for file:", fileId, error);
      setState(prev => ({
        ...prev,
        files: prev.files.map(f => f.id === fileId ? { ...f, status: FileStatus.Failed } : f)
      }));
    }
  };

  const handleUpload = async (file: File) => {
    if (file.size > 20 * 1024 * 1024) {
      alert(state.language === 'ar' ? 'حجم الملف كبير جداً (الأقصى 20 ميجابايت)' : 'File size is too large (max 20MB)');
      return;
    }

    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = reader.result as string;
      const mimeType = file.type || 'image/jpeg';

      const newFile: AttendanceFile = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        uploaded_by: state.user?.name || 'User',
        upload_date: new Date().toISOString(),
        status: FileStatus.Processing,
        previewUrl: base64
      };

      setState(prev => ({ ...prev, files: [newFile, ...prev.files] }));
      processFile(newFile.id, base64, mimeType);
    };
    reader.onerror = (e) => {
      console.error("FileReader error:", e);
      alert("Failed to read the file.");
    };
    reader.readAsDataURL(file);
  };

  const handleFileSelect = (file: AttendanceFile) => {
    if (file.status === FileStatus.Completed) {
      setSelectedFileId(file.id);
      setCurrentView('review');
    }
  };

  const handleUpdateFileData = (id: string, data: ExtractionResult) => {
    setState(prev => ({
      ...prev,
      files: prev.files.map(f => f.id === id ? { ...f, data } : f)
    }));
    alert(state.language === 'ar' ? 'تم حفظ التعديلات' : 'Changes saved successfully');
  };

  const selectedFile = state.files.find(f => f.id === selectedFileId);

  return (
    <HashRouter>
      <div dir={state.language === 'ar' ? 'rtl' : 'ltr'} className={state.language === 'ar' ? 'rtl-layout' : 'ltr-layout'}>
        {!state.user ? (
          <LoginPage onLogin={handleLogin} language={state.language} />
        ) : (
          <Layout 
            user={state.user} 
            language={state.language} 
            darkMode={state.darkMode} 
            onLogout={handleLogout}
            onLanguageToggle={handleLanguageToggle}
            onThemeToggle={handleThemeToggle}
          >
            {currentView === 'dashboard' ? (
              <DashboardPage 
                files={state.files} 
                onUpload={handleUpload} 
                language={state.language} 
                darkMode={state.darkMode}
                onFileSelect={handleFileSelect}
                onOpenDictionary={() => setCurrentView('dictionary')}
                dictionaryCount={state.nameDictionary.length}
              />
            ) : currentView === 'dictionary' ? (
              <DictionaryPage 
                names={state.nameDictionary}
                onAdd={handleAddName}
                onDelete={handleDeleteName}
                language={state.language}
                darkMode={state.darkMode}
                onBack={() => setCurrentView('dashboard')}
              />
            ) : selectedFile ? (
              <ReviewPage 
                file={selectedFile} 
                language={state.language} 
                darkMode={state.darkMode}
                onSave={handleUpdateFileData}
                onBack={() => setCurrentView('dashboard')}
              />
            ) : (
              <Navigate to="/" replace />
            )}
          </Layout>
        )}
      </div>
    </HashRouter>
  );
};

export default App;

