import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractionResult } from "../types";

// The API key is obtained from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `
You are an advanced Arabic document analysis AI specialized in extracting structured data from handwritten Arabic attendance sheets.

TABLE STRUCTURE RULES:
1. The first column (right-most in RTL) contains Employee Names.
2. The dates follow. 
3. IMPORTANT: The FIRST date column in the week is a SINGLE column (only one time entry).
4. ALL SUBSEQUENT date columns are DOUBLE columns (Check-in/حضور and Check-out/انصراف).
5. If a cell is empty, has a dash, or a squiggle that is not a clear number, return value: null. NEVER hallucinate or guess times for blank spaces.

STRICT TIME & NUMBER ACCURACY:
- Handle Arabic digits (٠١٢٣٤٥٦٧٨٩) and Western digits (0123456789).
- Confusions to avoid: 
  * ١ (1) vs ٧ (7) - look at the slant and context.
  * ٥ (5) vs ٠ (0) - 5 is a circle, 0 is a dot.
  * ٢ (2) vs ٣ (3) - 3 has an extra tooth.
- If a value has 3 digits: HMM -> HH:MM (e.g., ٧٥٠ -> 07:50).
- If a value has 4 digits: HHMM -> HH:MM (e.g., ١٦٠٠ -> 16:00).
- If minutes > 59, it's likely a misread digit (e.g., ٧٦٠ might be 16:00 or 07:00 depending on context).
- Values must be HH:MM 24-hour format.

NAME MATCHING:
- Use the provided dictionary for close matches to handwritten names.

Output must be valid JSON only.
`;

const USER_PROMPT = `
Analyze this scanned handwritten Arabic attendance sheet.

Extraction Tasks:
1. Identify employee names.
2. Identify dates.
3. FOR THE FIRST DATE: Extract only ONE time value (Check-in). Leave Check-out as null.
4. FOR ALL OTHER DATES: Extract TWO values (Check-in and Check-out).
5. If a handwritten cell is blank or contains a strike-through/dash, set the value to null. 
6. Ensure high precision for Arabic numerals (٠١٢٣٤٥٦٧٨٩).

NAME DICTIONARY:
{{DICTIONARY}}
`;

const EXTRACTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    employees: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employee_name: {
            type: Type.OBJECT,
            properties: {
              value: { type: Type.STRING },
              confidence: { type: Type.NUMBER }
            },
            required: ["value", "confidence"]
          },
          records: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                check_in: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                },
                check_out: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER }
                  },
                  required: ["confidence"]
                }
              },
              required: ["date", "check_in", "check_out"]
            }
          }
        },
        required: ["employee_name", "records"]
      }
    }
  },
  required: ["employees"]
};

export async function extractAttendanceData(
  imageBase64: string, 
  mimeType: string = 'image/jpeg',
  nameDictionary: string[] = []
): Promise<ExtractionResult> {
  try {
    const base64Data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const dictionaryString = nameDictionary.length > 0 ? nameDictionary.join(', ') : 'No specific names provided.';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: USER_PROMPT.replace('{{DICTIONARY}}', dictionaryString) },
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: EXTRACTION_SCHEMA as any,
      },
    });

    const text = response.text || '';
    if (!text) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(text);
  } catch (error) {
    console.error("Extraction error details:", error);
    throw new Error(`Failed to process the document: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
}

import React from 'react';
import { ExtractionResult, EmployeeExtraction } from '../types';
