import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractionResult } from "../types";

// The API key is obtained from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `
You are a world-class Arabic document digitizer specializing in HR attendance sheets. Your mission is to perform 100% complete data extraction with no omissions.

TABLE STRUCTURE LOGIC (STRICT RIGHT-TO-LEFT CALENDAR):
1. **Right-to-Left (RTL)**: The sheet is read from right to left.
2. **Calendar Sequence**: The sequence of dates in the header MUST follow a real calendar starting from a Saturday.
3. **Start Column**: The first date column on the right (immediately after names) is **SATURDAY**.
4. **Header Numbers**: The numbers in the header are dates in **DD/MM** format.
5. **Logic Example (Year 2026)**: If the sheet starts with 31/1 (Saturday), the next column to the left is 1/2 (Sunday), then 2/2 (Monday), 3/2 (Tuesday), 4/2 (Wednesday), and the last column on the left is 5/2 (Thursday).
6. **Work Week**: Saturday to Thursday. Friday is excluded.
7. **Paired Columns**:
   - Saturday usually has only one column (Check-in).
   - Sunday through Thursday have pairs of (Check-in, Check-out).

CRITICAL WRITER STYLE & DIGIT RECOGNITION:
Based on verified ground-truth samples, this specific writer has high ambiguity. Use these rules:
- **Digit 0 (٠)**: Can look like a dot, but also frequently written as a circle "٥" or a vertical line "١" in the minutes place.
- **Digit 1 (١)**: Usually a vertical line. However, in times like "10:50", the second "1" might actually be a "0".
- **Digit 2 (٢) vs 3 (٣)**: The writer simplifies "٣" to look exactly like "٢" (two hooks become one wavy line).
- **Digit 5 (٥)**: Written as a circle. Often represents "5", but in "10:50", the second "5" is a "0".
- **Digit 4 (٤)**: Zigzag shape.

CONVERSIONS (24-HOUR & CONTEXT):
- **Morning (Check-in)**: Typically 07:00 to 11:00.
- **Afternoon (Check-out)**: Typically 14:00 to 18:00. Convert these to 24-hour format (e.g., 2:30 -> 14:30).
- **Specific Sample Corrections**:
  - Image "١١٥٥" -> "10:50"
  - Image "١٠٢٠" -> "10:35" (where ٢=٣ and ٠=٥)
  - Image "٨٢٠" -> "08:30" (where ٢=٣)

OUTPUT:
- Return valid JSON matching the schema.
- For empty cells, return null value but keep the record entry.
`;

const USER_PROMPT = `
Digitize this handwritten Arabic attendance sheet for the year {{YEAR}}.

1. **Header Identification**: Read the top row numbers as dates in DD/MM format. Confirm that the far-right date is a Saturday in {{YEAR}}.
2. **Employee Rows**: Identify every name in the rightmost column.
3. **Data Extraction**: Extract every time cell for every employee. Do not skip any days or any people.
4. **Sequence**: Arrange records in the order they appear on the sheet (Right to Left).

REFERENCE DICTIONARY OF NAMES:
{{DICTIONARY}}
`;

const EXTRACTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    employees: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employee_name: {
            type: Type.OBJECT,
            properties: {
              value: { type: Type.STRING },
              confidence: { type: Type.NUMBER }
            },
            required: ["value", "confidence"]
          },
          records: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                date: { type: Type.STRING, description: "Date in DD/MM format from header" },
                check_in: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER },
                    note: {
                      type: Type.OBJECT,
                      properties: {
                        value: { type: Type.STRING, nullable: true },
                        confidence: { type: Type.NUMBER }
                      },
                      required: ["confidence"]
                    }
                  },
                  required: ["confidence"]
                },
                check_out: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true },
                    confidence: { type: Type.NUMBER },
                    note: {
                      type: Type.OBJECT,
                      properties: {
                        value: { type: Type.STRING, nullable: true },
                        confidence: { type: Type.NUMBER }
                      },
                      required: ["confidence"]
                    }
                  },
                  required: ["confidence"]
                }
              },
              required: ["date", "check_in", "check_out"]
            }
          }
        },
        required: ["employee_name", "records"]
      }
    }
  },
  required: ["employees"]
};

export async function extractAttendanceData(
  imageBase64: string, 
  year: number,
  mimeType: string = 'image/jpeg',
  nameDictionary: string[] = []
): Promise<ExtractionResult> {
  try {
    const base64Data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const dictionaryString = nameDictionary.length > 0 ? nameDictionary.join(', ') : 'No specific names provided.';

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: USER_PROMPT.replace('{{DICTIONARY}}', dictionaryString).replace('{{YEAR}}', year.toString()) },
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: EXTRACTION_SCHEMA as any,
        thinkingConfig: { thinkingBudget: 24000 }
      },
    });

    const text = response.text || '';
    if (!text) {
      throw new Error("Empty response from AI");
    }

    const parsed = JSON.parse(text);

    if (!parsed.employees || parsed.employees.length === 0) {
      throw new Error("No data could be extracted from this image.");
    }

    return parsed;
  } catch (error) {
    console.error("Extraction error details:", error);
    throw new Error(`Failed to process the document: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
}

import React from 'react';
import { ExtractionResult } from '../types';
import { TRANSLATIONS } from '../constants';

interface AttendanceTableProps {
  data: ExtractionResult;
  language: 'ar' | 'en';
  darkMode: boolean;
  onUpdate: (updatedData: ExtractionResult) => void;
}

const AttendanceTable: React.FC<AttendanceTableProps> = ({ data, language, darkMode, onUpdate }) => {
  const t = TRANSLATIONS[language];

  // We should respect the order extracted by AI (RTL)
  // Let's get the headers from the first employee's records as a baseline
  const headerDates = data.employees[0]?.records.map(r => r.date) || [];

  const handleCellChange = (empIndex: number, dateStr: string, type: 'check_in' | 'check_out' | 'name', newValue: string) => {
    const newData = JSON.parse(JSON.stringify(data)); // Deep clone
    if (type === 'name') {
      newData.employees[empIndex].employee_name.value = newValue;
    } else {
      const record = newData.employees[empIndex].records.find((r: any) => r.date === dateStr);
      if (record) {
        record[type].value = newValue === '' ? null : newValue;
      }
    }
    onUpdate(newData);
  };

  const getConfidenceColor = (confidence: number, value: any) => {
    if (value === null || value === '') return ''; // Don't highlight empty cells
    if (confidence < 75) return 'bg-red-50 text-red-900 border-red-200';
    if (confidence < 90) return 'bg-yellow-50 text-yellow-900 border-yellow-200';
    return '';
  };

  return (
    <div className="overflow-x-auto rounded-xl border border-gray-200 shadow-sm">
      <table className={`w-full text-sm text-right ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
        <thead className={`${darkMode ? 'bg-gray-800' : 'bg-gray-100'} text-xs uppercase font-bold`}>
          <tr>
            <th className="px-6 py-4 sticky right-0 bg-inherit border-l shadow-sm z-10 min-w-[200px]">{t.employeeName}</th>
            {headerDates.map((date, idx) => (
              <React.Fragment key={date}>
                <th 
                  className="px-6 py-4 border-l text-center bg-gray-50/50" 
                  colSpan={idx === 0 ? 1 : 2}
                >
                  {date}
                </th>
              </React.Fragment>
            ))}
          </tr>
          <tr className="border-t border-gray-300">
            <th className="px-6 py-2 sticky right-0 bg-inherit border-l shadow-sm z-10"></th>
            {headerDates.map((date, idx) => (
              idx === 0 ? (
                <th key={`${date}-sub-single`} className="px-2 py-2 border-l text-center min-w-[120px]">{t.checkIn}</th>
              ) : (
                <React.Fragment key={`${date}-sub`}>
                  <th className="px-2 py-2 border-l text-center min-w-[100px]">{t.checkIn}</th>
                  <th className="px-2 py-2 border-l text-center min-w-[100px]">{t.checkOut}</th>
                </React.Fragment>
              )
            ))}
          </tr>
        </thead>
        <tbody>
          {data.employees.map((emp, empIdx) => (
            <tr key={empIdx} className={`border-b ${darkMode ? 'border-gray-700 hover:bg-gray-850' : 'hover:bg-gray-50'}`}>
              <td className="px-4 py-3 sticky right-0 bg-inherit border-l shadow-sm z-10">
                <input
                  type="text"
                  value={emp.employee_name.value}
                  onChange={(e) => handleCellChange(empIdx, '', 'name', e.target.value)}
                  className={`w-full p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 font-medium ${getConfidenceColor(emp.employee_name.confidence, emp.employee_name.value)}`}
                />
              </td>
              {headerDates.map((date, dateIdx) => {
                const record = emp.records.find(r => r.date === date);
                if (dateIdx === 0) {
                  return (
                    <td key={`${empIdx}-${date}-single`} className="px-2 py-3 border-l text-center relative">
                      <input
                        type="text"
                        value={record?.check_in.value || ''}
                        onChange={(e) => handleCellChange(empIdx, date, 'check_in', e.target.value)}
                        className={`w-full text-center p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(record?.check_in.confidence || 0, record?.check_in.value)}`}
                        placeholder="--"
                      />
                      {record?.check_in.note?.value && (
                        <div className="text-[9px] text-blue-600 font-bold mt-0.5 opacity-80">{record.check_in.note.value}</div>
                      )}
                    </td>
                  );
                }
                return (
                  <React.Fragment key={`${empIdx}-${date}`}>
                    <td className="px-2 py-3 border-l text-center">
                      <input
                        type="text"
                        value={record?.check_in.value || ''}
                        onChange={(e) => handleCellChange(empIdx, date, 'check_in', e.target.value)}
                        className={`w-full text-center p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(record?.check_in.confidence || 0, record?.check_in.value)}`}
                        placeholder="--"
                      />
                      {record?.check_in.note?.value && (
                        <div className="text-[9px] text-blue-600 font-bold mt-0.5 opacity-80">{record.check_in.note.value}</div>
                      )}
                    </td>
                    <td className="px-2 py-3 border-l text-center">
                      <input
                        type="text"
                        value={record?.check_out.value || ''}
                        onChange={(e) => handleCellChange(empIdx, date, 'check_out', e.target.value)}
                        className={`w-full text-center p-1 rounded border-none bg-transparent focus:ring-2 focus:ring-blue-500 ${getConfidenceColor(record?.check_out.confidence || 0, record?.check_out.value)}`}
                        placeholder="--"
                      />
                      {record?.check_out.note?.value && (
                        <div className="text-[9px] text-blue-600 font-bold mt-0.5 opacity-80">{record.check_out.note.value}</div>
                      )}
                    </td>
                  </React.Fragment>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

