import * as XLSX from 'xlsx';
import { ExtractionResult } from '../types';

export function exportToExcel(data: ExtractionResult, fileName: string) {
  const wb = XLSX.utils.book_new();

  // Header dates as ordered in extraction (which respects AI extraction sequence)
  const headerDates = data.employees[0]?.records.map(r => r.date) || [];

  const headers = ['اسم الموظف'];
  headerDates.forEach((date, idx) => {
    if (idx === 0) {
      headers.push(`${date} (حضور)`);
      headers.push(`${date} (ملاحظة حضور)`);
    } else {
      headers.push(`${date} (حضور)`);
      headers.push(`${date} (ملاحظة حضور)`);
      headers.push(`${date} (انصراف)`);
      headers.push(`${date} (ملاحظة انصراف)`);
    }
  });

  const rows: any[] = [headers];

  data.employees.forEach(emp => {
    const row: any[] = [emp.employee_name.value];
    headerDates.forEach((date, idx) => {
      const record = emp.records.find(r => r.date === date);
      if (idx === 0) {
        row.push(record?.check_in?.value || '');
        row.push(record?.check_in?.note?.value || '');
      } else {
        row.push(record?.check_in?.value || '');
        row.push(record?.check_in?.note?.value || '');
        row.push(record?.check_out?.value || '');
        row.push(record?.check_out?.note?.value || '');
      }
    });
    rows.push(row);
  });

  const ws = XLSX.utils.aoa_to_sheet(rows);

  // Set sheet direction to RTL
  if (!ws['!views']) ws['!views'] = [];
  ws['!views'].push({ RTL: true });

  // Add some basic styling (column widths)
  const wscols = [{ wch: 30 }]; // First column wider for names
  for (let i = 1; i < headers.length; i++) {
    wscols.push({ wch: 15 });
  }
  ws['!cols'] = wscols;

  XLSX.utils.book_append_sheet(wb, ws, 'Attendance');
  XLSX.writeFile(wb, `${fileName}.xlsx`);
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractionResult } from "../types";

// The API key is obtained from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `
You are a specialized Arabic Handwriting Analyst for HR Attendance systems. 
The provided sheets are filled by MULTIPLE people, so styles vary significantly. 

AMBIGUITY RESOLUTION PROTOCOL:
1. **Digit Recognition (Visual & Contextual)**:
   - "١" (1) vs "٧" (7): If a check-in looks like 1, but most people arrive at 7, check if the stroke has a 'v' shape. Output the most logical time for an office shift.
   - "٣" (3) vs "٤" (4): Distinguish between "teeth" and "zigzags".
   - "٢٥" (25) vs "٥٠" (50): Crucial distinction. Check if the writer uses a circle for 5 or a dot for 0. Compare with other rows for consistency.
   - "٥" (5) vs "٠" (0): In Arabic, '0' is a dot and '5' is a circle. However, dots can be large and circles can be small. Use the 60-minute clock logic (e.g., 08:62 is impossible, so it must be 08:02 or 08:52).

2. **Time Normalization**:
   - People use various separators: ":" (colon), "." (dot), "," (comma), " " (space), or nothing.
   - **MANDATORY**: Convert ALL to "HH:MM" format.
   - If a cell says "٧٣٠", interpret as "07:30".
   - If a cell says "٨.٤٥", interpret as "08:45".

3. **Shift Context**:
   - Check-in: Usually 07:00 - 11:00.
   - Check-out: Usually 14:00 - 18:00. ALWAYS convert afternoon times to 24-hour format (e.g., 3:15 PM -> 15:15).

4. **Table Logic (Strict RTL)**:
   - Far right = Names.
   - Next column to the left = Saturday (Check-in only).
   - Following columns = Sun-Thu (Check-in/Check-out pairs).
   - DO NOT SKIP ROWS or COLUMNS. If a cell is blank or illegible, return null for the value but include the object in JSON.
`;

const USER_PROMPT = `
Process this multi-handwritten Arabic attendance sheet for the year {{YEAR}}.

IDENTIFICATION STEPS:
1. Identify the Header dates (DD/MM). Saturday should be on the far right.
2. Read Names using the provided Dictionary as a primary reference.
3. Extract times for every single cell. Apply the Ambiguity Resolution Protocol for 1vs7, 3vs4, and 25vs50.
4. If you see a note written next to a time (like 'إجازة' or 'مأمورية'), extract it into the 'note' field.

REFERENCE DICTIONARY OF NAMES:
{{DICTIONARY}}
`;

const EXTRACTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    employees: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employee_name: {
            type: Type.OBJECT,
            properties: {
              value: { type: Type.STRING },
              confidence: { type: Type.NUMBER }
            },
            required: ["value", "confidence"]
          },
          records: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                date: { type: Type.STRING, description: "Date in DD/MM format" },
                check_in: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true, description: "Normalized HH:MM" },
                    confidence: { type: Type.NUMBER },
                    note: {
                      type: Type.OBJECT,
                      properties: {
                        value: { type: Type.STRING, nullable: true },
                        confidence: { type: Type.NUMBER }
                      },
                      required: ["confidence"]
                    }
                  },
                  required: ["confidence"]
                },
                check_out: {
                  type: Type.OBJECT,
                  properties: {
                    value: { type: Type.STRING, nullable: true, description: "Normalized 24h HH:MM" },
                    confidence: { type: Type.NUMBER },
                    note: {
                      type: Type.OBJECT,
                      properties: {
                        value: { type: Type.STRING, nullable: true },
                        confidence: { type: Type.NUMBER }
                      },
                      required: ["confidence"]
                    }
                  },
                  required: ["confidence"]
                }
              },
              required: ["date", "check_in", "check_out"]
            }
          }
        },
        required: ["employee_name", "records"]
      }
    }
  },
  required: ["employees"]
};

export async function extractAttendanceData(
  imageBase64: string, 
  year: number,
  mimeType: string = 'image/jpeg',
  nameDictionary: string[] = []
): Promise<ExtractionResult> {
  try {
    const base64Data = imageBase64.includes(',') ? imageBase64.split(',')[1] : imageBase64;
    const dictionaryString = nameDictionary.length > 0 ? nameDictionary.join(', ') : 'No specific names provided.';

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { text: USER_PROMPT.replace('{{DICTIONARY}}', dictionaryString).replace('{{YEAR}}', year.toString()) },
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: EXTRACTION_SCHEMA as any,
        // Increased thinking budget for complex visual reasoning on handwriting
        thinkingConfig: { thinkingBudget: 24576 }
      },
    });

    const text = response.text || '';
    if (!text) {
      throw new Error("Empty response from AI");
    }

    const parsed = JSON.parse(text);

    if (!parsed.employees || parsed.employees.length === 0) {
      throw new Error("No data could be extracted from this image.");
    }

    return parsed;
  } catch (error) {
    console.error("Extraction error details:", error);
    throw new Error(`Failed to process the document: ${error instanceof Error ? error.message : 'Unknown error'}`);
  }
}

