                <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="admin@system.com" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">{t.password}</label>
                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="••••••••" />
              </div>
              <button onClick={() => onLogin({ email, password })} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition shadow-md mt-4">
                {t.login}
              </button>

              <div className="pt-6 border-t mt-4 grid grid-cols-2 gap-3">
                <label className="cursor-pointer bg-gray-100 hover:bg-gray-200 text-gray-700 py-2.5 rounded-xl font-bold transition text-sm text-center">
                  <i className="fas fa-sync-alt mr-1"></i> {t.switchDb}
                  <input type="file" className="hidden" accept=".json" onChange={(e) => e.target.files?.[0] && onImport(e.target.files[0])} />
                </label>
                <button onClick={onInitialize} className="bg-gray-100 hover:bg-gray-200 text-gray-700 py-2.5 rounded-xl font-bold transition text-sm">
                  <i className="fas fa-plus mr-1"></i> {t.newDatabase}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

