// --- Main App ---

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'dashboard' | 'review' | 'dictionary' | 'users' | 'samples'>('dashboard');
  const [selectedFileId, setSelectedFileId] = useState<string | null>(null);
  const [loginError, setLoginError] = useState(false);

  // Silent update to hard drive whenever state changes
  useEffect(() => {
    if (state.isDatabaseLoaded && globalFileHandle) {
      saveToSystemFile(state);
    }
  }, [state]);

  const saveToSystemFile = async (data: any) => {
    if (!globalFileHandle) return;
    try {
      const writable = await globalFileHandle.createWritable();
      const content = JSON.stringify(data, null, 2);
      await writable.write(content);
      await writable.close();
    } catch (err) { console.error("Auto-save failed", err); }
  };

  const handleConnectFile = async () => {
    try {
      const [handle] = await (window as any).showOpenFilePicker({ types: [{ description: 'JSON Database', accept: { 'application/json': ['.json'] } }] });
      const file = await handle.getFile();
      const content = await file.text();
      const importedState = JSON.parse(content);
      globalFileHandle = handle;
      setState({ ...INITIAL_STATE, ...importedState, isDatabaseLoaded: true, connectedFileName: file.name });
    } catch (err) { console.log("Picker cancelled or failed"); }
  };

  const handleCreateNewFile = async () => {
    try {
      const handle = await (window as any).showSaveFilePicker({ suggestedName: 'attendance_db.json', types: [{ description: 'JSON Database', accept: { 'application/json': ['.json'] } }] });
      globalFileHandle = handle;
      const file = await handle.getFile();
      setState({ ...INITIAL_STATE, isDatabaseLoaded: true, connectedFileName: file.name });
      saveToSystemFile(INITIAL_STATE);
    } catch (err) { console.log("Picker cancelled"); }
  };

  const handleLogin = (credentials: { email: string, password: string }) => {
    const user = state.users?.find(u => u.email === credentials.email && u.password === credentials.password);
    if (user) { setCurrentUser(user); setLoginError(false); } else { setLoginError(true); }
  };

  const handleUpdateUser = (u: User) => setState(p => ({ ...p, users: p.users.map(ex => ex.id === u.id ? u : ex) }));
  const handleDeleteUser = (id: string) => setState(p => ({ ...p, users: p.users.filter(u => u.id !== id) }));
  const handleAddUser = (u: User) => setState(p => ({ ...p, users: [...p.users, u] }));
  const handleDeleteFile = (id: string) => setState(p => ({ ...p, files: p.files.filter(f => f.id !== id) }));
  const handleUpdateFileData = (id: string, data: ExtractionResult) => setState(p => ({ ...p, files: p.files.map(f => f.id === id ? { ...f, data } : f) }));

  const handleUpload = (file: File, year: number) => {
    const reader = new FileReader(); reader.onload = () => {
      const base64 = reader.result as string;
      const newFile: AttendanceFile = { id: Math.random().toString(36).substr(2, 9), name: file.name, uploaded_by: currentUser?.name || 'User', upload_date: new Date().toISOString(), status: FileStatus.Processing, year: year, previewUrl: base64 };
      setState(p => ({ ...p, files: [newFile, ...p.files] }));
      processFile(newFile.id, base64, year, file.type);
    }; reader.readAsDataURL(file);
  };

  const processFile = async (id: string, base64: string, year: number, mime: string) => {
    try {
      const res = await extractAttendanceData(base64, year, mime, state.nameDictionary, state.visualReferences);
      setState(p => ({ ...p, files: p.files.map(f => f.id === id ? { ...f, status: FileStatus.Completed, data: res } : f) }));
    } catch (e) {
      setState(p => ({ ...p, files: p.files.map(f => f.id === id ? { ...f, status: FileStatus.Failed } : f) }));
    }
  };

  const selectedFile = state.files?.find(f => f.id === selectedFileId);

  return (
    <HashRouter>
      <div dir={state.language === 'ar' ? 'rtl' : 'ltr'} className={state.language === 'ar' ? 'rtl-layout' : 'ltr-layout'}>
        {!currentUser ? (
          <LoginPage onLogin={handleLogin} language={state.language} isDatabaseLoaded={state.isDatabaseLoaded} fileName={state.connectedFileName} onConnect={handleConnectFile} onCreate={handleCreateNewFile} error={loginError} onCloseError={() => setLoginError(false)} />
        ) : (
          <Layout user={currentUser} language={state.language} darkMode={state.darkMode} onLogout={() => setCurrentUser(null)} onLanguageToggle={() => setState(p => ({...p, language: p.language === 'ar' ? 'en' : 'ar'}))} onThemeToggle={() => setState(p => ({...p, darkMode: !p.darkMode}))} onSaveDatabase={() => saveToSystemFile(state)} onNavigate={setCurrentView} currentView={currentView} >
            {currentView === 'dashboard' ? <DashboardPage files={state.files} onUpload={handleUpload} onDelete={handleDeleteFile} language={state.language} darkMode={state.darkMode} onFileSelect={(f: any) => { setSelectedFileId(f.id); setCurrentView('review'); }} /> : 
             currentView === 'dictionary' ? <DictionaryPage names={state.nameDictionary} onAdd={(n: any) => setState(p => ({...p, nameDictionary: [...new Set([...p.nameDictionary, n])]}))} onDelete={(n: any) => setState(p => ({...p, nameDictionary: p.nameDictionary.filter(x => x !== n)}))} language={state.language} darkMode={state.darkMode} /> : 
             currentView === 'samples' ? <VisualDictionaryPage samples={state.visualReferences} onAdd={(d: any, i: any) => setState(p => ({...p, visualReferences: [...p.visualReferences, {id: Math.random().toString(), digit: d, imageBase64: i}]}))} onDelete={(id: any) => setState(p => ({...p, visualReferences: p.visualReferences.filter(r => r.id !== id)}))} language={state.language} darkMode={state.darkMode} /> : 
             currentView === 'users' ? <UserManagementPage users={state.users} onAdd={handleAddUser} onUpdate={handleUpdateUser} onDelete={handleDeleteUser} language={state.language} darkMode={state.darkMode} /> : 
             selectedFile ? <ReviewPage file={selectedFile} language={state.language} darkMode={state.darkMode} onSave={handleUpdateFileData} onBack={() => setCurrentView('dashboard')} /> : <Navigate to="/" replace />}
          </Layout>
        )}
      </div>
    </HashRouter>
  );
};

