  connectedFileName: undefined
};

// --- Helper Functions ---

const mergeState = (current: AppState, imported: any): AppState => {
  const merged = { ...current, ...imported };
  // Ensure we always have at least the default admin if no users exist
  if (!merged.users || merged.users.length === 0) {
    merged.users = [DEFAULT_ADMIN];
  } else {
    // Check if the admin exists, if not, add it for safety
    const hasAdmin = merged.users.some((u: User) => u.email === DEFAULT_ADMIN.email);
    if (!hasAdmin) merged.users.push(DEFAULT_ADMIN);
  }
  return merged;
};

